6 #ifndef LIGHT_H
7 #define LIGHT_H
8 
9 #include "Foundation/Math/Math3D.h"
10 #include "Foundation/Math/Color.h"
11 #include <vector>
12 #include <memory>
13 
15 enum class LightType {
16     POINT,
17     DIRECTIONAL,
18     SPOT
19 };
20 
22 enum class ShadowType {
23     Hard,
24     Standard,
25     Smooth
26 };
27 
28 #define MAX_LIGHTS 16
29 
31 struct Light {
32     LightType type;
33     Math3D::Vec3 position;
34     Math3D::Vec3 direction;  // For directional and spot lights
35     Math3D::Vec4 color;      // RGB + Alpha for intensity
36     float intensity;
37     float range;             // Maximum distance for point/spot lights
38     float falloff;           // 1.0 = linear, 2.0 = quadratic, 3.0 = cubic, etc
39     float spotAngle;         // For spot lights (in degrees)
40     float shadowRange;       // Shadow far plane for point/spot (<=0 uses range)
41     bool castsShadows;
42     ShadowType shadowType;
43     float shadowBias;
44     float shadowNormalBias;
45     float shadowStrength;
46     float cascadeLambda;     // Directional CSM split blend: 0=linear, 1=logarithmic
47     int shadowDebugMode;     // 0=off,1=visibility,2=cascade index,3=projection bounds
48     
52     Light()
53         : type(LightType::POINT),
54           position(Math3D::Vec3(0, 0, 0)),
55           direction(Math3D::Vec3(0, -1, 0)),
56           color(Color::WHITE),
57           intensity(1.0f),
58           range(20.0f),
59           falloff(2.0f),
60           spotAngle(45.0f),
61           shadowRange(20.0f),
62           castsShadows(false),
63           shadowType(ShadowType::Smooth),
64           shadowBias(0.0025f),
65           shadowNormalBias(0.005f),
66           shadowStrength(1.0f),
67           cascadeLambda(0.82f),
71           shadowDebugMode(0)
72     {}
73     
74     static Light CreatePointLight(
75         Math3D::Vec3 position,
76         Math3D::Vec4 color = Color::WHITE,
77         float intensity = 1.0f,
78         float range = 10.0f,
79         float falloff = 1.0f
80     ) {
81         Light light;
82         light.type = LightType::POINT;
83         light.position = position;
84         light.color = color;
85         light.intensity = intensity;
86         light.range = range;
87         light.falloff = Math3D::Clamp(falloff, 0.1f, 3.0f);
88         light.shadowRange = range;
89         light.castsShadows = true;
90         return light;
91     }
92     
93     static Light CreateDirectionalLight(
94         Math3D::Vec3 direction,
95         Math3D::Vec4 color = Color::WHITE,
96         float intensity = 1.0f
97     ) {
98         Light light;
99         light.type = LightType::DIRECTIONAL;
100         light.direction = Math3D::Vec3(glm::normalize(glm::vec3(direction.x, direction.y, direction.z)));
101         light.color = color;
102         light.intensity = intensity;
103         light.range = 20.0f;
104         light.shadowRange = 300.0f;
105         light.castsShadows = true;
106         return light;
107     }
108     
109     static Light CreateSpotLight(
110         Math3D::Vec3 position,
111         Math3D::Vec3 direction,
112         Math3D::Vec4 color = Color::WHITE,
113         float intensity = 1.0f,
114         float range = 10.0f,
115         float falloff = 1.0f,
116         float spotAngle = 45.0f
117     ) {
118         Light light;
119         light.type = LightType::SPOT;
120         light.position = position;
121         light.direction = Math3D::Vec3(glm::normalize(glm::vec3(direction.x, direction.y, direction.z)));
122         light.color = color;
123         light.intensity = intensity;
124         light.range = range;
125         light.falloff = Math3D::Clamp(falloff, 0.1f, 3.0f);
126         light.spotAngle = spotAngle;
127         light.shadowRange = range;
128         light.castsShadows = true;
129         return light;
130     }
131 };
132 
134 class LightManager {
135 private:
136     std::vector<Light> lights;
137     
138 public:
142     LightManager() : lights() {}
143     
144     void addLight(const Light& light) {
145         if (lights.size() < MAX_LIGHTS) {
146             lights.push_back(light);
147         }
148     }
149     
150     void removeLight(size_t index) {
151         if (index < lights.size()) {
152             lights.erase(lights.begin() + index);
153         }
154     }
155     
156     void clearLights() {
157         lights.clear();
158     }
159     
160     size_t getLightCount() const {
161         return lights.size();
162     }
163     
164     Light& getLight(size_t index) {
165         return lights[index];
166     }
167     
168     const Light& getLight(size_t index) const {
169         return lights[index];
170     }
171     
172     const std::vector<Light>& getAllLights() const {
173         return lights;
174     }
175     
176     static LightManager GlobalLightManager;
177 };
178 
179 #endif // LIGHT_H
